import React from "react";
import coreValuesImg from "../../../assets/images/core-values.png";
import coreFiveValuesImg from "../../../assets/images/core-5-values.png";
import Breadcrumb from "../../layout/breadcrumb";
import { color } from "@mui/system";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";

function WhyTurkey() {
  const [t, i18next] = useTranslation();

  return (
    <>
      <Breadcrumb title={t("Header.WhyTurkey")} />
      <div className="content">
        <div className="container">
          <div className="row">
            <div className="col-12">
              <div className="terms-content">
                {/* Why Turkey */}
                <div className="terms-text">
                  <h4>{t("Header.WhyTurkey")}</h4>
                  <p>
                    According to the World Tourism Organization- UN, Türkiye is
                    the sixth most visited tourism destination in the entire
                    world.
                  </p>
                  <p>
                    Over the years, it has also come to be a very popular
                    medical tourism destination with over half a million
                    tourists coming in annually for medical purposes.
                  </p>
                  <p>
                    Türkiye's share of the world's health tourism pie is growing
                    day by day and among the top 10 countries that export health
                    services to the world. Furthermore, it has risen to the top
                    five among the countries that receive visitors for medical
                    tourism recently.
                  </p>
                  <p>
                    According to records, during 2016 almost 200,000 medical
                    tourists visited Türkiye but this number skyrocketed where
                    approximately 700 thousand tourists came to receive health
                    services in 2019.{" "}
                  </p>
                  <p>
                    Although health tourism was adversely affected by the
                    Covid-19 pandemic in 2020, 2021 was the year the sector
                    caught the pre-pandemic patient figures where the number of
                    patients reached 1 million 300 thousand patients.
                  </p>
                  <p>
                    Istanbul, Ankara, Antalya, Izmir, Erzurum and Van are the
                    cities most preferred by international patients, whereas,
                    medical treatment branches most preferred by international
                    patients are dentistry, gynecology, ophthalmology, chest,
                    general surgery, internal diseases, orthopedics and
                    traumatology, oncology, cardiology, hair transplant,
                    ear-nose-throat and urology.
                  </p>
                </div>
                {/* /Why Turkey */}

                {/* Geographic location tying Europe with Asia  */}
                <div className="terms-text">
                  <h4>Geographic location tying Europe with Asia </h4>
                  <p>
                    Türkiye is located at the crossroads of the Balkans,
                    Caucasus, Middle East, and Mediterranean. Its land area is
                    greater than that of any European state. The larger part of
                    Türkiye is in Asia, comprising the Anatolia. The remainder
                    land lies in the extreme southeastern part of Europe.
                  </p>
                  <p>
                    Such a strategic location has enabled Türkiye to serve as a
                    commercial, political and cultural center for centuries.
                    Nowadays as well, its location offers excellent transport
                    links shortening the flight time wherever you are travelling
                    from.
                  </p>
                </div>
                {/* /Geographic location tying Europe with Asia  */}

                <div className="terms-text">
                  <h4>Charming renowned global touristic heading</h4>
                  <p>
                    Türkiye is an excellent touristic destination with its rich
                    history, pleasant climate and unique blend of Oriental and
                    European cultures.{" "}
                  </p>
                  <p>
                    According to the temporary data obtained from the General
                    Directorate of Security ; in Apri̇l 2022 the number of
                    foreign visitors arrived is over 2 million 5 hundred
                    thousand, which increased by over 225 % compared to the
                    previous year.
                  </p>
                  <p>
                    According to UNESCO World Heritage Center, Türkiye
                    encompasses 19 sites included in the World Heritage List,
                    most are cultural ones, in addition to 84 tentative sites.{" "}
                  </p>
                  <p>
                    Türkiye , where history, culture and extraordinary natural
                    beauties are intertwined, is one of the rare tourism
                    paradises of the world. It is a privileged country in terms
                    of its climate and natural resources where all the features
                    of the four seasons can always be experienced; green
                    forests, snowy mountains suitable for skiing, clean seas,
                    hot springs, and hospitable people.{" "}
                  </p>
                  <p>
                    <b>Turkish cuisine</b> “Türk mutfağı” is one of the three
                    most famous cuisines of the world. Whether you prefer a
                    vegetable stew rich in herbs, moderately seasoned skewers of
                    grilled meat, or steamed fish topped with a slice of lemon
                    you will always be satisfied. Furthermore, vegetarians can
                    enjoy a large number of delicious dishes. Dolma: stuffed
                    vegetables, Mercimek köfte: red lentil dish, and Imam
                    bayildi: eggplant dish are only few examples of vegetarian
                    friendly dishes.{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4>
                    Heavy government involvement, support and encouragement for
                    the medical sector{" "}
                  </h4>
                  <p>
                    Another supporting factor is the Turkish Government’s
                    support of health tourism, with a large percentage of the
                    overall investment being subsidized by the state. As a
                    result, medical tourism in turkey is offered in
                    cost-effective and high standard treatments .
                  </p>
                  <p>
                    Through passing the proper legislations and enhancing the
                    quality of the services in the field, the main goal of the
                    Turkish government is to be number one in the world in terms
                    of health tourism.{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4>
                    Proven track record of advanced medical treatment for a wide
                    range of ailments
                  </h4>

                  <p>
                    One reason why Türkiye is considered a prominent medical
                    destination is the compliance of its clinics, health
                    professionals and healthcare in general with the highest
                    international standards. For example, Istanbul has 20
                    medical organizations accredited by the Joint Commission
                    International (JCI).
                  </p>
                  <p>
                    Health facilities in Türkiye are equipped with latest
                    technologies operated by highly trained professionals. Due
                    to Türkiye’s high population density and diversity, and the
                    resulting large number of local and international patients,
                    its medical staff is well versed in dealing with medical
                    cases from all around the world.
                  </p>
                  <p>
                    Furthermore, most Turkish doctors complete their training in
                    North America and Europe before practicing in Türkiye.
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Short waiting times</h4>
                  <p>
                    With the aim of meeting the requirements of patients
                    travelling from other countries, you can schedule your
                    medical service in as little as two weeks, while in western
                    countries for example it is common to wait months or years
                    for the same treatment.
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Affordable medical services </h4>
                  <p>
                    In Türkiye High quality healthcare is offered by
                    internationally accredited clinics and medical professionals
                    at just a fraction of the total cost when compared with
                    other countries;
                  </p>
                  <p>
                    Surgical and medical procedures can be around 50-70% less
                    expensive in Türkiye than in many European countries for
                    example. Nevertheless, the quality of offered services is
                    unmatchable when compared with countries that offer low-cost
                    medical services.
                  </p>
                  <p>
                    Doing the math of the cost of travel, treatment and
                    accommodation the total is significantly less than if you
                    opted to have the same procedure in another country.{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Pleasant and smooth experience </h4>
                  <p>
                    Türkiye is both safe and easy to travel to with a regional
                    airport hub and flight connections to pretty much
                    everywhere. Furthermore, Türkiye has visa free access from
                    91 countries.{" "}
                  </p>
                  <p>
                    While in Türkiye, hospitals provide patients with
                    multilingual translators to facilitate communication with
                    doctors and health workers, especially with the services
                    provided by a proper intermediary.{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Fits-all-budgets destination</h4>
                  <p>
                    Türkiye, is a country that meets the demands of tourists and
                    offers accommodation options that range from supreme luxury
                    five-star hotels to the most affordable hostels or even
                    Airbnb. Similarly, different airlines, including Turkish
                    ones, offer a number of daily flights that include dırect as
                    well as cheaper indirect options.
                  </p>
                </div>

                <div className="terms-text">
                  <h4>A wide range of treatments</h4>
                  <p>
                    Türkiye offers a comprehensive choice of medical and
                    surgical procedures, including organ transplants, cancer
                    treatments, dentistry, IVF and hair transplants. Türkiye is
                    also a leading destination for wellness tourism, mental
                    health, weight loss, advanced age and “quit smoking” camps.
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Dental Care</h4>
                  <p>
                    Türkiye is one of the top-rated destinations for dental care
                    procedures due to the affordable prices and high quality.
                    Patients can save on average 50-70% for dental procedures
                    such as a full set of implants.
                  </p>
                  <p>
                    Some other procedures can be done in one sitting while
                    enjoying a vacation, such as teeth-whitening, dentures and
                    even crowns.{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Hair Transplantation </h4>
                  <p>
                    Türkiye is one of the best places to get have a hair
                    transplant due to the cost-savings and extremely high
                    standard of the clinics and hair transplant surgeons, the
                    majority of which hold internationally recognized
                    accreditation.
                  </p>
                </div>

                <div className="terms-text">
                  <h4>Wellness Tourism</h4>
                  <p>
                    Türkiye is a perfect option when travelling for the purpose
                    of promoting, maintaining and enhancing health and
                    well-being through physical, psychological, or spiritual
                    activities.
                  </p>
                  <p>
                    For example, thermal water can offer effective treatment for
                    rheumatic diseases with its high mineralization content and
                    effective therapeutic properties.{" "}
                  </p>
                  <p>
                    Türkiye has an extremely advantageous position in terms of
                    spa and thermal treatment due to natural resources and the
                    advantages of its climate that are not found in other
                    countries{" "}
                  </p>
                </div>

                <div className="terms-text">
                  <h4></h4>
                  <h4>Remarkable and affordable transport infrastructure </h4>
                  <p>
                    Road Transport system in Turkey offers numerous options for
                    citizens as well as tourists. The means comprise taxis,
                    minibuses, buses, bicycles, and even escooters.{" "}
                  </p>
                  <p>
                    Railway Transportation and high-speed train are of great
                    importance in Turkiye tying cities and areas from east to
                    west in the country.{" "}
                  </p>
                  <p>
                    An example is the vital Marmaray Project, a 76.6 km-long
                    (47.6 mi) intercontinental commuter rail line in Istanbul,
                    comprises a rail tunnel under the Bosphorus strait and
                    existing suburban railway lines along the Sea of Marmara.{" "}
                  </p>
                  <p>
                    Sea transportation in Turkey comprises a number of options
                    such as private ferries, ferries dedicated to transporting
                    cars, sea buses, and sea taxis, most of which offer a unique
                    experience due to the wonderful sea views the country
                    enjoys.
                  </p>
                  <p>
                    Air transport is also of a strategic importance where 36
                    international airports and 23 domestic ones are available.{" "}
                  </p>
                  <p>
                    Istanbul Airport is one of the world's most active. In the
                    year 2021, the number of passengers using the airport
                    reached 37,176,509 passengers, of which 26,586,306 were
                    international passengers.
                  </p>
                </div>
                <div className="terms-text">
                  <h4>Medical Tourism in Turkey</h4>
                  <div className="embed-responsive embed-responsive-16by9">
                    <iframe
                      className="embed-responsive-item"
                      src="https://www.youtube.com/embed/4DDZOF1Ba9Y?rel=0"
                    ></iframe>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

export default WhyTurkey;
